 135→        return [];
 136→    }
 137→
 138→    const {data, error} = await supabase
 139→        .from('galaxy_centroids')
 140→        .select('user_id, galaxy_x, galaxy_y, mean_embedding')
 141→        .in('user_id', userIds);
 142→
 143→    if(error){
 144→        console.warn('supabase warning while fetching universe centroids:', error.message);
 145→        return [];
 146→    }
