 151→const getUniverseEdges = async(userIds) => {
 152→    if(!Array.isArray(userIds) || userIds.length < 2){
 153→        return [];
 154→    }
 155→
 156→    const {data, error} = await supabase
 157→        .from('galaxy_edges')
 158→        .select('user_a, user_b, similarity')
 159→        .in('user_a', userIds)
