 602→export const getJournalsService = async(limit, userId, before) => {
 603→    if(isNaN(limit) || limit > 20 || limit < 1){
 604→        console.error('limit should be intiger, not below 1 and higher than 20');
 605→        throw {status: 400, error: 'limit should be intiger, not below 1 and higher than 20'};
 606→    }
 607→
 608→    const parsedLimit = parseInt(limit);
 609→
 610→    let query = supabase
 611→    .from('journals')
 612→    .select(`
 613→        *, users(*),
 614→        like_count: likes(count),
 615→        comment_count: comments(count),
 616→        bookmark_count: bookmarks(count),
 617→        repost_source:journals!repost_source_journal_id(
 618→            id, title, content, post_type, canvas_doc, created_at,
 619→            users(id, name, image_url, badge)
 620→        )
 621→        `)
 622→    .eq('privacy', 'public')
 623→    .order('created_at', {ascending: false})
 624→    .order('id', {ascending: false})
 625→    .limit(parsedLimit + 1);
 626→
 627→    if(before){
 628→        query = query.lt('created_at', before);
 629→    }
 630→
 631→    const {data, error} = await query;
 632→
 633→    if(error){
 634→        console.error('supabase error while fetching journals:', error.message);
 635→        throw{status: 500, error: 'supabase error while fetching journals'}
