1299→export const searchJournalsService = async(query, limit, userId) => {
1300→    const normalizedQuery = normalizeSearchQuery(query);
1301→    if(!normalizedQuery || normalizedQuery.length < SEARCH_QUERY_MIN_LENGTH){
1302→        throw {status: 400, error: `query should be at least ${SEARCH_QUERY_MIN_LENGTH} characters`};
1303→    }
1304→
1305→    if(isNaN(limit) || limit < 1 || limit > SEARCH_LIMIT_MAX){
1306→        throw {status: 400, error: `limit should be an integer between 1 and ${SEARCH_LIMIT_MAX}`};
1307→    }
1308→
1309→    const parsedLimit = parseInt(limit);
1310→    const fetchLimit = Math.min(parsedLimit * 3, 60);
1311→
1312→    const selectColumns = `
1313→        *,
1314→        users(*),
1315→        like_count: likes(count),
1316→        comment_count: comments(count),
1317→        bookmark_count: bookmarks(count)
1318→    `;
1319→
1320→    // Prefer semantic retrieval. If pgvector RPC is unavailable or errors,
1321→    // fallback to keyword search so endpoint still returns useful data.
1322→    try {
1323→        const queryEmbedding = await GenerateEmbeddings(normalizedQuery, '');
1324→
1325→        if(Array.isArray(queryEmbedding) && queryEmbedding.length > 0){
1326→            const {data: matches, error: matchError} = await supabase.rpc('match_public_journals', {
1327→                query_embedding: queryEmbedding,
1328→                match_count: fetchLimit,
1329→                similarity_threshold: 0.35
1330→            });
1331→
1332→            if(matchError){
1333→                console.error('semantic search rpc error:', matchError.message);
1334→            } else if(Array.isArray(matches) && matches.length > 0){
1335→                const matchIds = matches.map((row) => row.id);
1336→                const similarityMap = new Map(matches.map((row) => [row.id, row.similarity]));
1337→
1338→                const {data: journals, error: errorJournals} = await supabase
1339→                    .from('journals')
1340→                    .select(selectColumns)
1341→                    .in('id', matchIds)
1342→                    .eq('privacy', 'public');
1343→
1344→                if(errorJournals){
1345→                    console.error('supabase error while fetching semantic search journals:', errorJournals.message);
1346→                    throw {status: 500, error: 'supabase error while fetching semantic search journals'};
1347→                }
1348→
1349→                const journalById = new Map((journals || []).map((journal) => [journal.id, journal]));
1350→                const orderedSemantic = matchIds
1351→                    .map((id) => journalById.get(id))
1352→                    .filter(Boolean)
1353→                    .map((journal) => ({
1354→                        ...journal,
1355→                        similarity: similarityMap.get(journal.id) || null
1356→                    }));
1357→
1358→                const withInteraction = await attachUserInteractionFlags(orderedSemantic, userId);
1359→                const hasMore = withInteraction.length > parsedLimit;
1360→
1361→                return {
1362→                    data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1363→                    hasMore: hasMore,
1364→                    mode: 'semantic'
1365→                };
1366→            }
1367→        }
1368→    } catch (error) {
1369→        console.error('semantic embedding/search fallback error:', error?.message || error);
1370→    }
1371→
1372→    const escapedQuery = normalizedQuery.replace(/[%_]/g, (match) => `\\${match}`);
1373→
1374→    const [titleResult, contentResult] = await Promise.all([
1375→        supabase
1376→            .from('journals')
1377→            .select(selectColumns)
1378→            .eq('privacy', 'public')
1379→            .ilike('title', `%${escapedQuery}%`)
1380→            .order('created_at', {ascending: false})
1381→            .order('id', {ascending: false})
1382→            .limit(parsedLimit + 1),
1383→        supabase
1384→            .from('journals')
1385→            .select(selectColumns)
1386→            .eq('privacy', 'public')
1387→            .ilike('content', `%${escapedQuery}%`)
1388→            .order('created_at', {ascending: false})
1389→            .order('id', {ascending: false})
1390→            .limit(parsedLimit + 1)
1391→    ]);
1392→
1393→    if(titleResult.error || contentResult.error){
1394→        console.error('keyword search error:', titleResult.error?.message || contentResult.error?.message);
1395→        throw {status: 500, error: 'supabase error while searching journals'};
1396→    }
1397→
1398→    const keywordMap = new Map();
1399→    (titleResult.data || []).forEach((journal) => {
1400→        keywordMap.set(journal.id, journal);
1401→    });
1402→    (contentResult.data || []).forEach((journal) => {
1403→        if(!keywordMap.has(journal.id)){
1404→            keywordMap.set(journal.id, journal);
1405→        }
1406→    });
1407→
1408→    const keywordJournals = [...keywordMap.values()];
1409→
1410→    const withInteraction = await attachUserInteractionFlags(keywordJournals || [], userId);
1411→    const hasMore = withInteraction.length > parsedLimit;
1412→
1413→    return {
1414→        data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1415→        hasMore: hasMore,
1416→        mode: 'keyword'
1417→    };
1418→}
