1080→    if(token) headers["Authorization"] = `Bearer ${token}`;
1081→
1082→    const parsedLimit = Number(options?.limit ?? 200);
1083→    const params = new URLSearchParams();
1084→    params.set("limit", String(Number.isNaN(parsedLimit) ? 200 : parsedLimit));
1085→
1086→    if(options?.cursor){
1087→        params.set("cursor", String(options.cursor));
1088→    }
1089→
1090→    if(Array.isArray(options?.types) && options.types.length > 0){
1091→        params.set("types", options.types.join(","));
1092→    } else if(typeof options?.types === "string" && options.types.trim()){
1093→        params.set("types", options.types.trim());
1094→    }
